import instructor
from pydantic import BaseModel, Field
from vex import verify

class CustomerRecord(BaseModel):
    tenant_id: str
    region: str = Field(..., regex='^(eu|us|ap)-[a-z]+')
    email: str

@instructor.patch()
def extract_record(message: str, tenant_id: str) -> CustomerRecord:
    return client.chat.completions.create(
        model='gpt-4o',
        response_model=CustomerRecord,
        messages=[{'role': 'user', 'content': f"Extract: {message}"}],
    )

# Vex-wrapped compliant extraction
@verify({
    'policies': ['tenant-isolation'],
    'asserts': [f"response.tenant_id == '{tenant_id}'"]
})
def compliant_extract(message: str, tenant_id: str) -> CustomerRecord:
    return extract_record(message, tenant_id)

result = compliant_extract('John Doe john@acme.com EU region', 'acme-corp')

import { patch } from 'instructor'; // @instructor-ai/instructor

import { verify } from 'vex-sdk';

type CustomerRecord = {
  tenantId: string;
  region: `eu-${string}` | `us-${string}` | `ap-${string}`;
  email: string;
};

const client = patch(openai, { mode: 'json-schema' });

const extractRecord = async (message: string, tenantId: string): Promise<CustomerRecord> => {
  return client.chat.completions.create({
    model: 'gpt-4o',
    responseModel: {
      type: 'object',
      properties: {
        tenantId: { type: 'string' },
        region: { type: 'string', enum: ['eu-west', 'us-east', 'ap-sydney'] },
        email: { type: 'string', format: 'email' }
      },
      required: ['tenantId', 'region', 'email']
    },
    messages: [{ role: 'user', content: `Extract: ${message}` }],
  });
};

const compliantExtract = verify(
  extractRecord,
  {
    policies: ['enterprise-saas'],
    asserts: [`response.tenantId === '${tenantId}'`],
    logLevel: 'audit'
  }
);

const result = await compliantExtract('Jane Smith jane@beta.com US East', 'beta-inc');
